import{i as e,r as t,s as n,t as r}from"./app-D2SU73VA.js";import"./helloworld-THjBwPkR.js";var i=JSON.parse(`{"path":"/docs/%E7%AB%A0%E8%8A%82%E6%A6%82%E5%BF%B5.html","title":"章节概念","lang":"zh-CN","frontmatter":{"description":"说明Dvnge视觉小说引擎的章节系统，了解如何创建章节文件、配置章节列表、编写游戏逻辑。"},"filePathRelative":"docs/章节概念.md","git":{"createdTime":1781703562000,"updatedTime":1781703562000,"contributors":[{"name":"TTQWNTian","username":"TTQWNTian","email":"ttqwntian@qq.com","commits":1,"url":"https://github.com/TTQWNTian"}]}}`),a={name:`章节概念.md`};function o(r,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[e(`<h1 id="章节概念" tabindex="-1"><a class="header-anchor" href="#章节概念"><span>章节概念</span></a></h1><p>章节是使用Dvnge制作游戏的基本，它们是在 <code>章节/</code> 文件夹中的 <code>js</code> 文件，我们编写游戏的运行逻辑就是在这些文件中。</p><p><strong>那么该怎么使用呢？</strong></p><p>这里我们在 <code>章节/</code> 文件夹中创建一个 <code>示例.js</code> 文件,然后里面写上这样的代码：</p><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code class="language-javascript"><span class="line"><span class="token keyword">var</span> 示例 <span class="token operator">=</span> <span class="token punctuation">[</span></span>
<span class="line">    <span class="token punctuation">{</span></span>
<span class="line">        <span class="token literal-property property">角色</span><span class="token operator">:</span> <span class="token string">&quot;Tian&quot;</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token literal-property property">内容</span><span class="token operator">:</span> <span class="token string">&quot;你好，世界。&quot;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>之后保存代码文件，这样就写好了一个基础的对话（现在看不懂为什么这么写不要紧，之后都会详细讲解）。</p><p>当然只创建文件是不起作用的，我们还需要在 <code>TTQ视觉小说引擎.js</code> 中加上所添加的章节路径。</p><p>在 <code>TTQ视觉小说引擎.js</code> 文件中找到 章节文件列表（大概在第十二行左右），然后在末尾添加这一行的代码：</p><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code class="language-javascript"><span class="line"><span class="token punctuation">{</span> <span class="token literal-property property">名称</span><span class="token operator">:</span> <span class="token string">&quot;示例&quot;</span><span class="token punctuation">,</span> <span class="token literal-property property">路径</span><span class="token operator">:</span> <span class="token string">&quot;章节/示例.js&quot;</span> <span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>加上后完整的 <code>章节文件列表</code> 代码是这样的：</p><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code class="language-javascript"><span class="line"><span class="token keyword">const</span> 章节文件列表 <span class="token operator">=</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token punctuation">{</span> <span class="token literal-property property">名称</span><span class="token operator">:</span> <span class="token string">&quot;示例&quot;</span><span class="token punctuation">,</span> <span class="token literal-property property">路径</span><span class="token operator">:</span> <span class="token string">&quot;章节/示例.js&quot;</span> <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>下载的引擎文件可能还会有“序章”，那个可以暂时先删掉，替换为本教学的“示例”，然后再用搜索替换来把 <code>TTQ视觉小说引擎.js</code> 的所有“序章”文本换成“示例”。</p><p>这样添加章节的配置就完成了！运行 <code>game.html</code> 就可以看到我们写的对话了。</p><p><img src="/docsImg/helloworld.webp" alt="helloworld.webp"></p>`,14)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};